SELECT qVendItem.[Model Item No_] AS SalesArt, qVendItem.[Variable Code 01] AS SalesColorCode, qVendItem.[Variable Code 02] AS Taglia, qVendItem.[Order Variable Code], qVendItem.No_, qVendItem.AssortmentCode, Sum(qVendItem.QuantitySold) AS QuantitySold, Sum(qVendItem.PairsSold) AS PairsSold, Sum(qVendItem.ValueSold) AS ValueSold, Sum(qVendItem.GrossSalesValue) AS GrossSalesValue, Sum(qVendItem.DiscountValue) AS DiscountValue, Sum(qVendItem.AreaManagerCommissionValue) AS AreaManagerCommissionValue, Sum(qVendItem.SalesPersonCommissionValue) AS SalesPersonCommissionValue, Sum(qVendItem.QuantityShipped) AS QuantityShipped, Sum(qVendItem.PairsShipped) AS PairsShipped, Sum(qVendItem.ValueShipped) AS ValueShipped, Sum(qVendItem.QuantityInvoiced) AS QuantityInvoiced, Sum(qVendItem.PairsInvoiced) AS PairsInvoiced, Sum(qVendItem.ValueInvoiced) AS ValueInvoiced
FROM qVendItem
GROUP BY qVendItem.[Model Item No_], qVendItem.[Variable Code 01], qVendItem.[Variable Code 02], qVendItem.[Order Variable Code], qVendItem.No_, qVendItem.AssortmentCode;

